{
  "executive_summary": "The courier assignment system contains a fundamental CAP theorem conflict between requirement #2 (strong consistency — no double-assignment) and requirement #3 (high availability during database node failure). During a network partition, the system cannot simultaneously guarantee both properties. This must be resolved by the product team before a specific architecture can be committed to. Two viable resolution paths are presented: consistency-first (safe but briefly unavailable during failures) and availability-first (always up but requires conflict resolution for rare double-assignments).",

  "architecture": {
    "components": [
      { "name": "Order Ingestion API", "responsibility": "Receives order placement requests, validates payload, and dispatches to the Assignment Engine. Must respond within 200ms including assignment.", "boundaries": "Stateless HTTP/gRPC layer. No business logic beyond validation." },
      { "name": "Assignment Engine", "responsibility": "Core domain logic: selects the optimal available courier based on proximity, capacity, and status. Executes the assignment atomically.", "boundaries": "Owns the assignment algorithm and courier selection criteria. Does not own courier profiles or order lifecycle." },
      { "name": "Courier Availability Store", "responsibility": "Maintains real-time courier availability state. This is the critical consistency boundary — the single source of truth for whether a courier is currently assigned.", "boundaries": "Tightly scoped to courier assignment status. Not a general courier data store." },
      { "name": "Courier Location Index", "responsibility": "Geospatial index of courier positions for proximity-based selection. Eventually consistent is acceptable here.", "boundaries": "Read-optimized. Fed by courier GPS pings. Staleness of a few seconds is tolerable." },
      { "name": "Assignment Event Publisher", "responsibility": "Publishes assignment events for downstream consumers (notifications, tracking, analytics).", "boundaries": "Async. Decouples assignment from downstream side effects." }
    ],
    "interfaces": [
      { "from": "Order Ingestion API", "to": "Assignment Engine", "contract": "assignCourier(orderId, pickupLocation, deliveryLocation) → { courierId, estimatedPickup } | AssignmentError", "coupling_type": "synchronous — must be in the 200ms path" },
      { "from": "Assignment Engine", "to": "Courier Location Index", "contract": "findNearbyCouriers(location, radius, limit) → Courier[]", "coupling_type": "synchronous read, eventually consistent data" },
      { "from": "Assignment Engine", "to": "Courier Availability Store", "contract": "claimCourier(courierId, orderId) → success | AlreadyAssigned", "coupling_type": "synchronous, strongly consistent write — this is the critical path" },
      { "from": "Assignment Engine", "to": "Assignment Event Publisher", "contract": "emit(CourierAssigned { orderId, courierId, timestamp })", "coupling_type": "asynchronous fire-and-forget" }
    ],
    "data_flow": "1) Order API receives request → 2) Assignment Engine queries Location Index for nearby couriers → 3) Engine attempts atomic claim on Courier Availability Store (compare-and-swap on courier status) → 4) On success, returns assignment; on conflict, retries with next candidate → 5) Assignment event published async. The entire 1-4 path must complete within 200ms, which is achievable with a single-region deployment and in-memory or Redis-based availability store.",
    "patterns_used": []
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Assignment",
        "classification": "core",
        "aggregates": [
          "CourierAssignment (aggregate root: courierId — invariant: a courier can hold at most one active assignment at a time)"
        ]
      },
      {
        "name": "Courier Availability",
        "classification": "core",
        "aggregates": [
          "CourierStatus (aggregate root: courierId — tracks: available, assigned, offline)"
        ]
      },
      {
        "name": "Order Intake",
        "classification": "supporting",
        "aggregates": [
          "Order (aggregate root: orderId — lifecycle: placed → assigned → picked_up → delivered)"
        ]
      },
      {
        "name": "Courier Location",
        "classification": "generic",
        "aggregates": [
          "CourierPosition (value object: courierId + lat/lng + timestamp)"
        ]
      }
    ],
    "context_map": [
      { "upstream": "Order Intake", "downstream": "Assignment", "relationship": "Customer-Supplier — Order Intake triggers assignment but Assignment owns the algorithm" },
      { "upstream": "Courier Availability", "downstream": "Assignment", "relationship": "Shared Kernel — tightly coupled by necessity; the availability state IS the consistency boundary" },
      { "upstream": "Courier Location", "downstream": "Assignment", "relationship": "Conformist — Assignment consumes location data as-is, tolerating eventual consistency" }
    ]
  },

  "trade_offs": [
    {
      "decision": "CAP resolution — Consistency-first (CP) approach",
      "gains": "Zero double-assignments. Simple mental model. No conflict resolution code. Easier for 2-person team to reason about.",
      "sacrifices": "During a DB node failure or leader election (typically 5-30 seconds), assignment requests will fail or queue. Brief unavailability windows.",
      "alternatives_considered": [
        "AP approach with conflict resolution: always available, but requires last-write-wins or merge logic to resolve double-assignments, adding significant complexity for a 2-person team",
        "Hybrid: CP for writes (claims), AP for reads (location queries) — more nuanced but adds operational complexity"
      ]
    },
    {
      "decision": "Single-node Redis with AOF persistence as Courier Availability Store",
      "gains": "Sub-millisecond compare-and-swap operations easily meeting 200ms budget. Simple ops. Single-writer eliminates distributed consensus overhead.",
      "sacrifices": "Single point of failure. If Redis goes down, assignments stop. Sentinel or failover adds recovery time.",
      "alternatives_considered": [
        "PostgreSQL with SELECT FOR UPDATE — strong consistency but higher latency (5-15ms per claim vs <1ms for Redis)",
        "Redis Cluster — distributed but introduces complexity around hash slots and split-brain risk",
        "etcd/Zookeeper — strong consistency with leader election, but overkill operational burden for 2 engineers"
      ]
    },
    {
      "decision": "Retry-with-next-candidate on assignment conflict",
      "gains": "Handles race conditions gracefully without distributed locks. Simple loop: try courier A, if claimed, try courier B.",
      "sacrifices": "Worst-case latency increases with contention. In extreme cases (many orders, few couriers), may exhaust 200ms budget.",
      "alternatives_considered": [
        "Pre-locking couriers — reserves before assigning, but adds lock management complexity",
        "Queue-based serial assignment — eliminates races entirely but adds latency and a SPOF"
      ]
    }
  ],

  "flexibility_points": [
    { "area": "Assignment algorithm", "evolution_path": "The selection criteria (proximity, rating, load balancing) are isolated in the Assignment Engine. Can evolve from simple nearest-courier to ML-based optimization without touching the consistency layer." },
    { "area": "Availability Store technology", "evolution_path": "The claimCourier interface is a simple compare-and-swap. Can swap Redis for DynamoDB conditional writes, PostgreSQL advisory locks, or any store supporting atomic conditional updates." },
    { "area": "Downstream event consumers", "evolution_path": "Assignment Event Publisher decouples all downstream concerns. Adding notifications, analytics, or audit trails requires zero changes to the assignment path." }
  ],

  "rigidity_points": [
    { "area": "Courier Availability Store consistency model", "reason": "This is the load-bearing wall. Whatever consistency model is chosen (CP or AP) fundamentally shapes the rest of the system. Changing this later requires rearchitecting conflict resolution, error handling, and client retry logic." },
    { "area": "200ms latency budget", "reason": "Constrains the assignment to a single synchronous call chain. Cannot introduce async steps, multi-round consensus, or cross-region replication in the hot path without violating this SLA." }
  ],

  "risks": [
    {
      "risk": "CAP conflict between requirements #2 and #3 is unresolved — the system cannot guarantee both strong consistency and high availability during a database partition",
      "severity": "critical",
      "mitigation": "Product team must decide: accept brief unavailability during failures (CP) OR accept rare double-assignments with compensation logic (AP). See escalation."
    },
    {
      "risk": "Redis single-point-of-failure if chosen as availability store",
      "severity": "high",
      "mitigation": "Redis Sentinel for automatic failover (adds 5-15s recovery window). Alternatively, Redis with synchronous replication to a standby. Accept that during failover, assignments are briefly unavailable (consistent with CP choice)."
    },
    {
      "risk": "200ms budget under contention — high-volume order spikes with few available couriers could exhaust retry budget",
      "severity": "medium",
      "mitigation": "Pre-filter candidates to 3-5 nearest couriers. Use optimistic concurrency with fast retry. Monitor P99 latency. Circuit-break if no courier assignable within budget."
    },
    {
      "risk": "Operational burden on 2-person team",
      "severity": "medium",
      "mitigation": "Minimize moving parts. Use managed services (e.g., AWS ElastiCache for Redis, managed PostgreSQL). Avoid distributed consensus systems that require deep operational expertise."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "",
    "files_to_create_or_modify": [],
    "patterns_to_follow": "Optimistic concurrency with compare-and-swap for courier claims. Retry-with-next-candidate on conflict. Aggregate root per courier for assignment invariant. Event-driven for all downstream side effects. Keep the hot path (order → assign) to exactly one synchronous write.",
    "pitfalls_to_avoid": [
      "Do NOT use distributed locks (e.g., Redlock) — they are neither safe nor performant for this use case. Use atomic compare-and-swap instead.",
      "Do NOT replicate courier state across regions if strong consistency is chosen — cross-region replication latency will blow the 200ms budget.",
      "Do NOT build a custom consensus protocol — use a proven store with built-in atomic operations.",
      "Do NOT couple assignment success to downstream notifications — keep the event publisher async to protect the latency budget.",
      "Do NOT over-engineer for the 2-person team — a monolith with clear module boundaries is far better than microservices here."
    ]
  },

  "escalations": [
    {
      "type": "contradictory_requirements",
      "description": "Requirements #2 (strong consistency: no double-assignment) and #3 (high availability during DB node failure) directly conflict under the CAP theorem. During a network partition or node failure, the system must choose: (A) reject assignment requests to preserve consistency, or (B) accept assignments with risk of double-assignment to preserve availability. Both cannot be guaranteed simultaneously — this is a proven impossibility result, not a design limitation.",
      "routed_to": "Bird",
      "options": [
        "Option A — Consistency-first (CP): Use a single-leader store (Redis with Sentinel, PostgreSQL with streaming replication). During leader failure, assignments are unavailable for 5-30 seconds while a new leader is elected. Zero double-assignments guaranteed. Simpler codebase. Recommended for a 2-person team.",
        "Option B — Availability-first (AP): Use a multi-master store or accept eventual consistency. Assignments always succeed, but rare double-assignments (estimated <0.01% under normal conditions) must be detected and compensated (e.g., reassign one order). Requires conflict resolution logic, adding ~30% more code complexity.",
        "Option C — Pragmatic hybrid: Consistency-first with a fast failover target (<5s) and client-side retry with backoff. Accept that 'high availability' means 99.95% uptime (26 minutes downtime/year) rather than 100%. This is the most common real-world resolution."
      ],
      "recommendation": "Option C (pragmatic hybrid) best balances all four requirements including team size. But this is a product decision — the business must accept the availability trade-off explicitly."
    }
  ],

  "confidence": {
    "level": 50,
    "high_confidence_areas": [
      "The CAP conflict is real and must be resolved before committing to an architecture",
      "200ms latency is achievable with in-memory or Redis-based stores in a single-region deployment",
      "Optimistic concurrency with compare-and-swap is the right primitive for preventing double-assignment",
      "A modular monolith is the right deployment topology for a 2-person team"
    ],
    "low_confidence_areas": [
      "Cannot recommend a specific architecture until the product team resolves the consistency vs availability trade-off",
      "Without knowing order volume, courier fleet size, and geographic distribution, cannot size the system or validate the 200ms budget under load"
    ],
    "assumptions": [
      "Single-region deployment (cross-region would make 200ms impossible with strong consistency)",
      "Courier fleet size is in the hundreds-to-thousands range, not millions",
      "Order volume does not exceed thousands per second (at which point the architecture changes significantly)",
      "'Database node fails' means a single node in a replicated cluster, not a full datacenter outage"
    ]
  }
}

